</Group>
<Group description="Sidebar Colors" selector="div.sidebar">
<Variable name="cloud.bg.color" description="Cloud Labels Color" type="color" default="#f4961e" value="#f4961e"/>
<Variable name="list.text.color" description="List Labels Color" type="color" default="#333333" value="#333333"/>
<Variable name="email.bg.color" description="Email Subscription Color" type="color" default="#803dec" value="#803dec"/>
<Variable name="email.text.color" description="Email Subscription Text Color" type="color" default="#ffffff" value="#ffffff"/>
</Group>
<Group description="Footer Subscribe Form" selector="#footer-form-wrap">
<Variable name="footer.email.title" description="Footer Email title" type="color" default="#ffffff" value="#ffffff"/>
</Group>
<Group description="Footer Colors" selector="div#llmflii">
<Variable name="footer.background.color" description="Footer Background  Color" type="color" default="#15202b" value="#15202b"/>
<Variable name="footer.gadgets.title" description="Footer Gadget Title Color" type="color" default="#e8e8e8" value="#e8e8e8"/>
<Variable name="footer.title.color" description="Footer Title Color" type="color" default="#e8e8e8" value="#e8e8e8"/>
<Variable name="footer.about.color" description="Footer About Us Color" type="color" default="#868686" value="#868686"/>
<Variable name="footer.text.color" description="Footer Text Color" type="color" default="#d7d7d7" value="#d7d7d7"/>
<Variable name="footer.copyright.bg" description="Footer Copyright Background Color" type="color" default="#0e151d" value="#0e151d"/>
</Group>
<Group description="Theme Fonts" selector="body">
<Variable name="main.font" description="Site Font" type="font" family="Raleway" default="normal 400 14px $(family)" value="normal 400 14px $(family)"/>
<Variable name="title.font" description="Title Font" type="font" family="Raleway" default="normal 400 14px $(family)" value="normal 400 14px $(family)"/>
<Variable name="meta.font" description="Meta Font" type="font" family="Raleway" default="normal 400 14px $(family)" value="normal 400 14px $(family)"/>
<Variable name="text.font" description="Text Font" type="font" family="Raleway" default="normal 400 14px $(family)" value="normal 400 14px $(family)"/>
</Group>
<Group description="Theme Widths" selector="body">
<Variable name="outerContainer.width" description="Theme Body Width" type="length" default="1145px" min="900px" max="1600px" value="1145px"/>
<Variable name="sidebar.width" description="Sidebar Width" type="length" default="320px" min="300px" max="500px" value="320px"/>
</Group>
<Group description="Reset (All Theme Fonts)">
<!-- Site Font -->
<Variable name="mainfont.normal" description="Main Font Normal" type="font" default="normal 500 14px $(main.font.family)" value="normal 500 14px $(family)"/>
<Variable name="mainfont.italic" description="Main Font Italic" type="font" default="italic 400 14px $(main.font.family)" value="italic 400 14px $(family)"/>
<Variable name="mainfont.semibold" description="Main Font SemiBold" type="font" default="normal 600 14px $(main.font.family)" value="normal 600 14px $(family)"/>
<Variable name="mainfont.semibolditalic" description="Main Font SemiBold Italic" type="font" default="italic 600 14px $(main.font.family)" value="italic 600 14px $(family)"/>
<Variable name="mainfont.bold" description="Main Font Bold" type="font" default="normal 700 14px $(main.font.family)" value="normal 700 14px $(family)"/>
<Variable name="mainfont.bolditalic" description="Main Font Bold Italic" type="font" default="italic 700 14px $(main.font.family)" value="italic 700 14px $(family)"/>
<!-- Title Font -->
<Variable name="titlefont.italic" description="Title Font Italic" type="font" default="italic 400 14px $(title.font.family)" value="italic 400 14px $(family)"/>
<Variable name="titlefont.normal" description="Title Font Normal" type="font" default="normal 500 14px $(title.font.family)" value="normal 500 14px $(family)"/>
<Variable name="titlefont.normalitalic" description="Title Font Normal Italic" type="font" default="italic 500 14px $(title.font.family)" value="italic 500 14px $(family)"/>
<Variable name="titlefont.semibold" description="Title Font SemiBold" type="font" default="normal 600 14px $(title.font.family)" value="normal 600 14px $(family)"/>
<Variable name="titlefont.semibolditalic" description="Title Font SemiBold Italic" type="font" default="italic 600 14px $(title.font.family)" value="italic 600 14px $(family)"/>
<Variable name="titlefont.bold" description="Title Font Bold" type="font" default="normal 700 14px $(title.font.family)" value="normal 700 14px $(family)"/>
<Variable name="titlefont.bolditalic" description="Title Font Bold Italic" type="font" default="italic 700 14px $(title.font.family)" value="italic 700 14px $(family)"/>
<!-- Meta Font -->
<Variable name="metafont.italic" description="Meta Font Italic" type="font" default="italic 400 14px $(meta.font.family)" value="italic 400 14px $(family)"/>
<Variable name="metafont.normal" description="Meta Font Normal" type="font" default="normal 500 14px $(meta.font.family)" value="normal 500 14px $(family)"/>
<Variable name="metafont.normalitalic" description="Meta Font Normal Italic" type="font" default="italic 500 14px $(meta.font.family)" value="italic 500 14px $(family)"/>
<!-- Text Font -->
<Variable name="textfont.italic" description="Text Font Italic" type="font" default="italic 400 14px $(text.font.family)" value="italic 400 14px $(family)"/>
<Variable name="textfont.normal" description="Text Font Normal" type="font" default="normal 500 14px $(text.font.family)" value="normal 500 14px $(family)"/>
<Variable name="textfont.normalitalic" description="Text Font Normal Italic" type="font" default="italic 500 14px $(text.font.family)" value="italic 500 14px $(family)"/>
<Variable name="textfont.semibold" description="Text Font SemiBold" type="font" default="normal 600 14px $(text.font.family)" value="normal 600 14px $(family)"/>
<Variable name="textfont.semibolditalic" description="Text Font SemiBold Italic" type="font" default="italic 600 14px $(text.font.family)" value="italic 600 14px $(family)"/>
<Variable name="textfont.bold" description="Text Font Bold" type="font" default="normal 700 14px $(text.font.family)" value="normal 700 14px $(family)"/>
<Variable name="textfont.bolditalic" description="Text Font Bold Italic" type="font" default="italic 700 14px $(text.font.family)" value="italic 700 14px $(family)"/>
</Group>
<!-- Extra Variables -->
<Variable name="body.background.color" description="Body Background Color" type="color" default="transparent" value="transparent"/>
<Variable name="body.post.color" description="Body Post Color" hideEditor="true" type="color" default="#ffffff" value="#ffffff"/>
<Variable name="body.text.font" description="Font" hideEditor="true" type="font" default="13px arial, sans-serif" value="13px arial, sans-serif"/>
<Variable name="body.text.color" description="Body Text Color" hideEditor="true" type="color" default="#6d6d6d" value="#6d6d6d"/>
<Variable name="body.title.color" description="Comments Color" hideEditor="true" type="color" default="#232323" value="#232323"/>
<Variable name="body.link.color" description="Body Link Color" hideEditor="true" type="color" default="#6d6d6d" value="#6d6d6d"/>
<Variable name="body.action.font.large" description="Comments Font 2" hideEditor="true" type="font" default="normal 700 14px Arial, sans-serif !important" value="normal 700 14px, Arial, sans-serif !important"/>
*/

/*-- Material Icons Font --*/
@font-face{font-family:'Material Icons Round';font-style:normal;font-weight:400;src:url(https://fonts.gstatic.com/s/materialiconsround/v105/LDItaoyNOAY6Uewc665JcIzCKsKc_M9flwmP.woff2) format('woff2');}.material-icons-round,.material-symbols-rounded{font-family:'Material Icons Round';font-weight:normal;font-style:normal;font-size:24px;line-height:1;vertical-align:middle;letter-spacing:normal;text-transform:none;display:inline-block;white-space:nowrap;word-wrap:normal;direction:ltr;-webkit-font-feature-settings:'liga';-webkit-font-smoothing:antialiased;}

html.rtl {
--body-font: 'Cairo',sans-serif;
--meta-font: 'Cairo',sans-serif;
--title-font: 'Cairo',sans-serif;
--text-font: 'Cairo',sans-serif;
}
:root{
--body-font:'$(main.font.family)', sans-serif;
--title-font:'$(title.font.family)', sans-serif;
--meta-font:'$(meta.font.family)', sans-serif;
--text-font:'$(text.font.family)', sans-serif;
--text-font-color:$(text.post.inner);
--runs-solid-color:#c1bbbb;
--black-color:#404040;
--hero-color:#aaaaaa;
--main-menu-bg:linear-gradient(45deg, $(main.menu.bg), $(main.menu.bg1));
--snippet-color:#aba4a4;
--solid-border:#ddd;
--featured-posts-title:$(featured.posts.title);
--button-bg-color:$(main.button.color);
--button-text-color:$(main.button.text.color);
--lables-buttons-color:$(lables.buttons.color);
--lables-text-color:$(lables.text.color);
--email-bg-color:$(email.bg.color);
--email-text-color:$(email.text.color);
--cloud-bg-color:$(cloud.bg.color);
--cloud-border-color:$(cloud.bg.color);
--list-text-color:$(list.text.color);
--theme-text-color:$(theme.text.color);
--featured-gadgets-title:$(featured.gadgets.title);
--placeholder-text-color:#3e3e3e;
--main-menu-text-color:$(main.menu.text.color);
--sub-menu-text-color:$(sub.menu.text.color);
--footer-title-color:$(footer.title.color);
--footer-copyright-bg:$(footer.copyright.bg);
--body-color-main:$(body.background);
--all-link-color:$(main.link.color);
--black-text:#343434;
--main-text-color:$(main.text.color);
--rRlLmii-bg:$(mobile.menu.bg.color);
--white-bg:#ffffff;
--block-bg:#ffffff;
--paint-cards:#f7faff;
--featured-posts-title-featured:#ffffff;
--white-label-color:#ffffff;
--color-section:$(color.section);
--color-section1:$(color.section1);
--color-section-text:$(color.section.text);
--bg-cards:#ffffff;
--bg-cards-video:#121212;
--bg-cards-shadow:0px 3px 3px 0 rgb(33 33 33 / 0.03);
--bt-breaking:rgba(0 0 0 / 0.08);
--bt-breaking-text:#626262;
--shadow-top:0 0 20px rgba(0,0,0,.15);
--shadow-top-fixed:5px 5px 8px 0px rgba(224 223 223 / 0.48);
--ads-bg:rgb(143 183 255 / 0.20);
--ads-text:#898989;
--buttons-category-text:#1d1d1d;
--snip-text-color:#eeeeee;
--search-bt-text:$(featured.posts.title);
--comments-dec:#333;
--sticky-bg:#f1f1f1;
--input-form:transparent;
--footer-email-title:$(footer.email.title);
--bt-home:#f2f7fb;
--cm-count:#555555;
--shadow-light:0px 2px 5px 1px rgb(0 0 0 / 0.10);
--xliil-text:#4e4e4e;
--sticky-lists:#f7fcff;
--post-snip-data:#707070;
--post-snip-open:#383838;
--ico-relative:#ff0000;
--front-bg-lists:#fff;
--share-author-links:#585858;
--box-posts-share:#f1f1f1;
--title-share:#1c1c1c;
--title-share-fa:#5c5c5c;
--footer-text-color:$(footer.text.color);
--footer-about-text:$(footer.about.color);
--footer-bg-color:$(footer.background.color);
--footer-gadgets-title:$(footer.gadgets.title);
--main-logo-text-color:$(main.logo.text.color);
--submenu-bg-color:$(submenu.background.color);
--comment-content:#f6f6f6;
--comment-text:#5e5e5e;
--label-text-color:#2c2c2c;
--pager-text-color:$(body.text.color);
--back-top:rgb(90 90 90 / 0.18);
--box-shadows:rgb(102 102 102 / 0.13);
}
a,abbr,acronym,address,applet,b,big,blockquote,body,caption,center,cite,code,dd,del,dfn,div,dl,dt,em,fieldset,font,form,h1,h2,h3,h4,h5,h6,html,i,iframe,img,ins,kbd,label,legend,li,object,p,pre,q,s,samp,small,span,strike,strong,sub,sup,table,tbody,td,tfoot,th,thead,tr,tt,u,ul,var{padding:0;border:0;outline:0;vertical-align:baseline;background:0;margin:0;text-decoration:none;}
form,textarea,input,button{font-family:var(--body-font);-webkit-appearance:none;-moz-appearance:none;appearance:none;border-radius:0;box-sizing:border-box}
input[type="radio"]{-webkit-appearance:auto;appearance:auto;}
.CSS_LIGHTBOX{z-index:999999!important}.CSS_LIGHTBOX_ATTRIBUTION_INDEX_CONTAINER .CSS_HCONT_CHILDREN_HOLDER > .CSS_LAYOUT_COMPONENT.CSS_HCONT_CHILD:first-child > .CSS_LAYOUT_COMPONENT{opacity:0}
input,textarea{outline:none;border: none;}
html{position:relative;word-break:break-word;word-wrap:break-word;text-rendering:optimizeLegibility;-webkit-font-smoothing:antialiased;-webkit-text-size-adjust:100%;}
/*! normalize.css v3.0.1 | MIT License | git.io/normalize */
dl,ul{list-style-position:inside;font-weight:400;list-style:none}
button{cursor: pointer;outline: none;border: none;}
ul li{list-style:none}
caption,th{text-align:center}
.box-view #outer-wrapper{max-width: 1190px;}
html,body{text-size-adjust:none;-webkit-text-size-adjust:none;-moz-text-size-adjust:none;-ms-text-size-adjust:none}
.separator a{clear:none!important;float:none!important;margin-left:0!important;margin-right:0!important}
#Navbar1,#navbar-iframe,.widget-item-control,a.quickedit,.home-link,.feed-links{display:none!important}
.center{display:table;margin:0 auto;position:relative}
.widget > h2,.widget > h3{display:none}
iframe[src*="youtube.com"]{width:100%;height:auto;aspect-ratio:16/9}
.widget iframe,.widget img{max-width:100%}
.post-body img:not(.snip-thumbnail){width:auto;height:auto;border:none;}
.container{position:relative;max-width: 100%;width: $(outerContainer.width);}
a,a:visited{text-decoration:none}
.clearfix{clear:both}
.section,.widget,.widget ul{margin:0;padding:0}
a{color:var(--all-link-color)}
abbr{text-decoration:none}
.widget>h2,.widget>h3{display:none}
*:before,*:after{-webkit-box-sizing:border-box;-moz-box-sizing:border-box;box-sizing:border-box;}
/*-- CSS Variables --*/
.no-items.section,#zqiilo{display:none}
.cookie-choices-info{display:none !important;}
div#custom-ads-placeholder{display:none;}
.blogger-clickTrap{position:unset !important;}
h1,h2,h3,h4,h5,h6{font-family:var(--title-font);font-weight:600}
body{position:relative;background:var(--body-color-main);background-repeat:repeat;background-attachment: fixed;background-position:top;background-position:left;font-family:var(--body-font);font-size:14px;font-weight:400;color:var(--black-text);word-wrap:break-word;margin:0;padding:0;font-style:normal;line-height:1.4}
#outer-wrapper{position:relative;overflow:hidden;width:100%;max-width:100%;margin:0 auto}
.outer-container{display: flex;justify-content: space-between;}
.post-body h1{font-size:28px}
.post-body h2{font-size:24px}
.post-body h3{font-size:21px}
.post-body h4{font-size:18px}
.post-body h5{font-size:16px}
.post-body h6{font-size:13px}
.home #feed-view, .search-view #feed-view, .label-view #feed-view{width:100%}
#center-container{position:relative;float:left;width:100%;overflow:hidden;padding:10px 0 0;margin:0}
#feed-view{position:relative;float:left;width:calc(100% - ($(sidebar.width) + 5px));box-sizing:border-box;padding:0}
#sidebar-container{position:relative;float:right;width:$(sidebar.width);box-sizing:border-box;padding:0}
.post-filter-image{position:relative;display:block;transition:transform .3s ease}
.snip-thumbnail{position:relative;width:100%;height:100%;display:block;object-fit:cover;z-index:1;opacity:0;transition:opacity .30s ease,transform .30s ease}
#h1-hide{display:none;visibility:hidden}
h1.blog-title{font-size:24px;max-width:195px;overflow:hidden;text-decoration:none;text-overflow:ellipsis;white-space:nowrap;line-height: 38px;}
.snip-thumbnail.lazy-img{opacity:1}
.row{position:relative;}
.post-filter-link:hover .snip-thumbnail{filter: brightness(0.9);}
.background-layer:before{content:'';position:absolute;left:0;right:0;bottom:0;height:66%;background-image:linear-gradient(to bottom,transparent,rgba(0,0,0,0.80));-webkit-backface-visibility:hidden;backface-visibility:hidden;z-index:2;opacity:1;margin:0;transition:opacity .25s ease}
.zeicilo a:before,.bpost-share a:before{display:inline-block;font-family:'Font Awesome 6 Brands';font-style:normal;font-weight:400;vertical-align: middle;}
.zeicilo .rss a:before,.social .rss a:before{content:'\e0e5';font-family:'Material Icons Round';}
.zeicilo .email a:before,.social .email a:before{content:'\e158';font-family:'Material Icons Round';}
.zeicilo .external-link a:before,.social .external-link a:before{content:'\e894';font-family:'Material Icons Round';}
.colorful a:hover {opacity: 0.8;}
.zeicilo a:before{content:var(--fa);}
.colorful .blogger a{color:#ff5722}
.colorful .facebook a{color:#1877F2}
.colorful .twitter a{color:#00acee}
.colorful .youtube a{color:#f50000}
.colorful .messenger a{color:#0084ff}
.colorful .snapchat a{color:#ffe700}
.colorful .telegram a{color:#179cde}
.colorful .instagram a{color:#dd277b}
.colorful .pinterest a{color:#ca2127}
.colorful .google a{color:#0165b4}
.colorful .apple a{color:#000000}
.colorful .microsoft a{color:#0165b4}
.colorful .dribbble a{color:#ea4c89}
.colorful .linkedin a{color:#0077b5}
.colorful .tiktok a{color:#fe2c55}
.colorful .stumbleupon a{color:#eb4823}
.colorful .vk a{color:#4a76a8}
.colorful .stack-overflow a{color:#f48024}
.colorful .github a{color:#24292e}
.colorful .soundcloud a{background:linear-gradient(#ff7400,#ff3400)}
.colorful .behance a{color:#191919}
.colorful .digg a{color:#1b1a19}
.colorful .delicious a{color:#0076e8}
.colorful .codepen a{color:#000}
.colorful .flipboard a{color:#f52828}
.colorful .reddit a{color:#ff4500}
.colorful .tumblr a{color:#365069}
.colorful .twitch a{color:#6441a5}
.colorful .rss a{color:#ffc200}
.colorful .skype a{color:#00aff0}
.colorful .whatsapp a{color:#3fbb50}
.colorful .discord a{color:#7289da}
.colorful .share a{color:var(--hero-color)}
.colorful .email a{color:#888}
.colorful .external-link a{color:#275bff}
.bpost-share a.fa-facebook,.bpost-share a.fa-facebook{background:#1877F2}
.bpost-share a.fa-x-twitter{background:#00acee}
.bpost-share a.fa-whatsapp{background:#3fbb50}
.zeipilo-logo{display:none}
#top-menu .selectnav{display:none}
.header-room{display:flex;flex-wrap:wrap;flex-direction:row;justify-content:space-between;align-items:center;align-content:center;}
.mega-flex .section{width:50%;}
.zeitdilo{position:relative;background-color:rgb(0 0 0 / 0.36);display:flex;align-items:center;font-size:12px;color: var(--button-text-color);width:40px;height:20px;margin:0 5px;border-radius:20px;}
.zeitdilo:hover:before{opacity:0.8}
.zeitdilo:before{content:'\e518';font-family:'Material Icons Round';position:absolute;left:2px;width:16px;height:16px;text-align:center;background-color:var(--button-bg-color);font-weight:400;line-height:16px;z-index:2;border-radius:50%;box-shadow:0 0 4px rgb(0 0 0 / 0.10);transition:left .18s ease;}
.zeitdilo:after{content:'\ea46';font-family:'Material Icons Round';position:absolute;right:4px;width:10px;font-size:8px;font-weight:400;line-height:1;text-align:center;opacity:0.5;transition:right .18s ease;}
#zeivilo>.mega-menu{position:unset!important}
.ijjpiIf li:hover .ijjgiIf{opacity:1;visibility:visible}
.drop-down>a:after{content:'\e5cf';float:right;font-family:'Material Icons Round';font-size:9px;font-weight:400;margin:-1px 0 0 5px}
