body#layout #custom-ads-placeholder .section{width:49%}
body#layout .row{display:flex}
body#layout div#promo-ok > h4:after{content:' - Put ad code to show ads inside posts/pages'}
div#paint-category,div#tint-category1{overflow:hidden !important;}
body#layout .zjilo,body#layout .search-toggle,body#layout #nav-search{display:none}
body#layout .header-section{width: 100%;}
body#layout .header-left{display:flex;}
body#layout #header-room1,.ijjpiIf{width:50%;}
body#layout #mega-wrap .widget, .rtl body#layout .add_widget a{display:block}
body#layout .search-toggle,body#layout .section-sticky{display:none}
body#layout #mega-wrap .widget{display:block}
body#layout #paint-category .widget,body#layout #tint-category1 .widget{float:left;width:49%;margin-right:1%;}
body#layout #center-container{margin:0}
body#layout #center-container>.container{display:flex;margin:auto}
body#layout #feed-view{width:68.66%;padding:0}
body#layout #sidebar-container{width:33.33%;padding:0;display:block}
body#layout .sidebar .widget,body#layout .sidebar .widget-content{float:none;overflow:visible}
body#layout .footer-outer{display:flex;}
body#layout div#footer-checks-menu,body#layout div#footer-copyright{overflow:hidden!important;width:100%}
body#layout .Footer-adv{overflow:hidden !important;}
body#layout .Footer-adv div.widget{float:left !important;width:49% !important;}
body#layout div#LinkList7{margin-left:1% !important;}
body#layout .section > h4:after{font-size:12px;font-size:12px;font-weight:400;}
body#layout #admin > h4:after{content:' - For setting up comments system, related posts, button texts.'}
body#layout #header-room1 > h4:after{content:' - Set Main Logo here'}
body#layout #ijjpiIf > h4:after{content:' - Edit menu and submenu links here'}
body#layout #color-section > h4:after{content:' - Set homepage title,caption,images etc.'}
body#layout  #footer-form > h4:after{content:' - Footer Subsribe Form'}
body#layout #paint-category > h4:after{content:'  - Set different categories from here'}
body#layout #paint-category1 > h4:after{content:'  - Set different categories from here'}
body#layout #head-title1 > h4:after{content:'  - Set title for categories'}
body#layout #tint-category1 > h4:after{content:'  - Set different categories from here'}
body#layout #paint-category1 > h4:after{content:'  - Set different categories from here'}
body#layout #bottom-widget > h4:after{content:' - Bottom Featured Posts Section'}
body#layout #main-ads1 > h4:after{content:' - Ads Section place ad code here'}
body#layout #main > h4:after{content:' - Recent Posts,Comments,no. of Posts etc.'}
body#layout #main-ads-below > h4:after{content:' - Below recent Posts ads section (responsive)'}
body#layout #main-ads2 > h4:after{content:' - Top and Bottom Posts Ads'}
body#layout #zfilo > h4:after{content:' - Change footer logo and caption'}
body#layout #footer-checks-menu > h4:after{content:' - Footer Pages Links'}
body#layout #footer-copyright > h4:after{content:' - Footer Copyright Link'}
body#layout #sidebar > h4:after{content:' - Sidebar widgets'}
body#layout #cookies > h4:after{content:' - Change Cookies Consent from here'}

